import { DEMO_MODE, DEMO_AGENCY_ID } from '@/lib/config';
import { apiClient } from '@/lib/api/client';
import { mapDeliverer, mapContract, mapCommission, mapFreelancer } from '@/lib/api/mappers';
import { mockDeliverers, mockContracts, mockCommissions, mockFreelancers, mockStaffMembers, mockBranches } from '@/lib/mock-data';
import { staffMemberToManagerFields } from '@/lib/staff-utils';
import type { Deliverer, Contract, CommissionRecord, FreelancerAssociation, StaffMember, StaffRole, StaffStatus } from '@/lib/types';
import type { DelivererDto, ContractDto, CommissionRecordDto, FreelancerAssociationDto } from '@/lib/api/dto';

export const staffService = {
  // ── Personnel administratif ───────────────────────────────

  async getStaffMembers(agencyId = DEMO_AGENCY_ID): Promise<StaffMember[]> {
    if (DEMO_MODE) return mockStaffMembers;
    const dtos = await apiClient.get<StaffMember[]>(`/agencies/${agencyId}/staff`);
    return dtos;
  },

  async registerStaffMember(agencyId: string, data: {
    fullName: string;
    phone: string;
    email?: string;
    role: StaffRole;
    branchId?: string;
  }): Promise<StaffMember> {
    if (DEMO_MODE) {
      const id = `MGR-${String(mockStaffMembers.length).padStart(3, '0')}`;
      const branch = data.branchId
        ? mockBranches.find(b => b.id === data.branchId)
        : undefined;
      const member: StaffMember = {
        id,
        agencyId: 'AGN-001',
        fullName: data.fullName,
        phone: data.phone,
        email: data.email ?? '',
        role: data.role,
        status: 'ACTIVE',
        joinedAt: new Date().toISOString().slice(0, 10),
        ...(branch ? { branchId: branch.id, branchName: branch.name } : {}),
      };
      mockStaffMembers.push(member);
      if (branch && (data.role === 'BRANCH_MANAGER' || data.role === 'OPERATIONS_MANAGER')) {
        Object.assign(branch, staffMemberToManagerFields(member));
      }
      return member;
    }
    return apiClient.post<StaffMember>(`/agencies/${agencyId}/staff`, data);
  },

  async updateStaffMember(memberId: string, data: {
    fullName?: string;
    phone?: string;
    email?: string;
    role?: StaffRole;
    branchId?: string;
  }): Promise<void> {
    if (DEMO_MODE) {
      const member = mockStaffMembers.find(m => m.id === memberId);
      if (!member) return;

      if (data.fullName !== undefined) member.fullName = data.fullName;
      if (data.phone !== undefined) member.phone = data.phone;
      if (data.email !== undefined) member.email = data.email;
      if (data.role !== undefined) member.role = data.role;

      if (data.branchId !== undefined) {
        const prevBranchId = member.branchId;
        const nextBranchId = data.branchId || undefined;

        if (prevBranchId && prevBranchId !== nextBranchId) {
          const prevBranch = mockBranches.find(b => b.id === prevBranchId);
          if (prevBranch?.managerId === memberId) {
            prevBranch.managerId = undefined;
            prevBranch.managerName = undefined;
            prevBranch.managerEmail = undefined;
            prevBranch.managerPhone = undefined;
          }
        }

        if (nextBranchId) {
          const branch = mockBranches.find(b => b.id === nextBranchId);
          if (branch) {
            if (branch.managerId && branch.managerId !== memberId) {
              const prevManager = mockStaffMembers.find(m => m.id === branch.managerId);
              if (prevManager) {
                prevManager.branchId = undefined;
                prevManager.branchName = undefined;
              }
            }
            member.branchId = branch.id;
            member.branchName = branch.name;
            if (['BRANCH_MANAGER', 'OPERATIONS_MANAGER', 'AGENCY_MANAGER'].includes(member.role)) {
              Object.assign(branch, staffMemberToManagerFields(member));
            }
          }
        } else {
          member.branchId = undefined;
          member.branchName = undefined;
        }
      } else if (member.branchId) {
        const branch = mockBranches.find(b => b.id === member.branchId);
        if (branch?.managerId === memberId) {
          Object.assign(branch, staffMemberToManagerFields(member));
        }
      }
      return;
    }
    await apiClient.patch(`/staff/${memberId}`, data);
  },

  async suspendStaffMember(memberId: string): Promise<void> {
    if (DEMO_MODE) {
      const member = mockStaffMembers.find(m => m.id === memberId);
      if (member) member.status = 'SUSPENDED';
      return;
    }
    await apiClient.patch(`/staff/${memberId}/suspend`, {});
  },

  async reactivateStaffMember(memberId: string): Promise<void> {
    if (DEMO_MODE) {
      const member = mockStaffMembers.find(m => m.id === memberId);
      if (member) member.status = 'ACTIVE';
      return;
    }
    await apiClient.patch(`/staff/${memberId}/reactivate`, {});
  },

  // ── Livreurs ──────────────────────────────────────────────

  async getDeliverers(agencyId = DEMO_AGENCY_ID): Promise<Deliverer[]> {
    if (DEMO_MODE) return mockDeliverers;
    const dtos = await apiClient.get<DelivererDto[]>(`/agencies/${agencyId}/deliverers`);
    return dtos.map(mapDeliverer);
  },

  async registerDeliverer(agencyId: string, data: {
    fullName: string; phone: string; email?: string;
    delivererType: string; branchId?: string;
  }): Promise<Deliverer> {
    if (DEMO_MODE) return mockDeliverers[0];
    const dto = await apiClient.post<DelivererDto>(`/agencies/${agencyId}/deliverers`, data);
    return mapDeliverer(dto);
  },

  async suspendDeliverer(delivererId: string): Promise<void> {
    if (DEMO_MODE) return;
    await apiClient.patch(`/deliverers/${delivererId}/suspend`, {});
  },

  async reactivateDeliverer(delivererId: string): Promise<void> {
    if (DEMO_MODE) return;
    await apiClient.patch(`/deliverers/${delivererId}/reactivate`, {});
  },

  async attachToBranch(delivererId: string, branchId: string): Promise<void> {
    if (DEMO_MODE) return;
    await apiClient.patch(`/deliverers/${delivererId}/branch`, { branchId });
  },

  // ── Contrats ──────────────────────────────────────────────

  async getContracts(agencyId = DEMO_AGENCY_ID): Promise<Contract[]> {
    if (DEMO_MODE) return mockContracts;
    const dtos = await apiClient.get<ContractDto[]>(`/agencies/${agencyId}/contracts`);
    return dtos.map(mapContract);
  },

  async createContract(delivererId: string, data: {
    contractType: string; startDate: string; endDate?: string;
    remunerationModel: string; baseSalary?: number; commissionRate?: number; currency: string;
  }): Promise<Contract> {
    if (DEMO_MODE) return mockContracts[0];
    const dto = await apiClient.post<ContractDto>(`/deliverers/${delivererId}/contracts`, data);
    return mapContract(dto);
  },

  async terminateContract(contractId: string): Promise<void> {
    if (DEMO_MODE) return;
    await apiClient.delete(`/contracts/${contractId}`);
  },

  async renewContract(contractId: string, data: { endDate?: string }): Promise<void> {
    if (DEMO_MODE) return;
    await apiClient.post(`/contracts/${contractId}/renew`, data);
  },

  // ── Commissions ───────────────────────────────────────────

  async getCommissions(agencyId = DEMO_AGENCY_ID): Promise<CommissionRecord[]> {
    if (DEMO_MODE) return mockCommissions;
    const dtos = await apiClient.get<CommissionRecordDto[]>(`/agencies/${agencyId}/commissions`);
    return dtos.map(mapCommission);
  },

  async payCommission(commissionId: string): Promise<void> {
    if (DEMO_MODE) return;
    await apiClient.patch(`/commissions/${commissionId}/pay`, {});
  },

  async disputeCommission(commissionId: string, reason: string): Promise<void> {
    if (DEMO_MODE) return;
    await apiClient.post(`/commissions/${commissionId}/dispute`, { reason });
  },

  // ── Freelancers ───────────────────────────────────────────

  async getFreelancers(agencyId = DEMO_AGENCY_ID): Promise<FreelancerAssociation[]> {
    if (DEMO_MODE) return mockFreelancers;
    const dtos = await apiClient.get<FreelancerAssociationDto[]>(`/agencies/${agencyId}/freelancers`);
    return dtos.map(mapFreelancer);
  },

  async associateFreelancer(agencyId: string, data: {
    freelancerActorId: string; commissionRate: number; startDate: string;
  }): Promise<FreelancerAssociation> {
    if (DEMO_MODE) return mockFreelancers[0];
    const dto = await apiClient.post<FreelancerAssociationDto>(`/agencies/${agencyId}/freelancers`, data);
    return mapFreelancer(dto);
  },

  async terminateFreelancer(associationId: string): Promise<void> {
    if (DEMO_MODE) return;
    await apiClient.delete(`/freelancers/${associationId}`);
  },

  async suspendFreelancer(associationId: string): Promise<void> {
    if (DEMO_MODE) return;
    await apiClient.patch(`/freelancers/${associationId}/suspend`, {});
  },

  async cancelFreelancerInvitation(associationId: string): Promise<void> {
    if (DEMO_MODE) return;
    await apiClient.delete(`/freelancers/${associationId}/invitation`);
  },
};
