import { DEMO_MODE, DEMO_AGENCY_ID } from '@/lib/config';
import { apiClient } from '@/lib/api/client';
import { mapHub, mapHubParcelRecord, toBackendHubStatus } from '@/lib/api/mappers';
import { mockHubs, mockHubParcels } from '@/lib/mock-data';
import type { Hub, HubParcelRecord, HubStatus } from '@/lib/types';
import type { HubDto, HubParcelRecordDto } from '@/lib/api/dto';

export const hubService = {
  async getHubs(agencyId = DEMO_AGENCY_ID): Promise<Hub[]> {
    if (DEMO_MODE) return mockHubs;
    const dtos = await apiClient.get<HubDto[]>(`/agencies/${agencyId}/hubs`);
    return dtos.map(mapHub);
  },

  async getHub(hubId: string): Promise<Hub> {
    if (DEMO_MODE) return mockHubs.find(h => h.id === hubId) ?? mockHubs[0];
    const dto = await apiClient.get<HubDto>(`/hubs/${hubId}`);
    return mapHub(dto);
  },

  async createHub(agencyId: string, data: {
    name: string; code: string; capacityUnits: number;
    city: string; country: string; street?: string;
    retentionDelayHours?: number; branchId?: string;
  }): Promise<Hub> {
    if (DEMO_MODE) return { ...mockHubs[0], id: crypto.randomUUID(), name: data.name };
    const dto = await apiClient.post<HubDto>(`/agencies/${agencyId}/hubs`, data);
    return mapHub(dto);
  },

  async updateHubStatus(hubId: string, status: HubStatus): Promise<void> {
    if (DEMO_MODE) return;
    await apiClient.patch(`/hubs/${hubId}/status`, { status: toBackendHubStatus(status) });
  },

  async getParcelRecords(hubId: string): Promise<HubParcelRecord[]> {
    if (DEMO_MODE) return mockHubParcels.filter(p => p.hubId === hubId);
    const dtos = await apiClient.get<HubParcelRecordDto[]>(`/hubs/${hubId}/parcels`);
    return dtos.map(mapHubParcelRecord);
  },

  async getAllParcelRecords(agencyId = DEMO_AGENCY_ID): Promise<HubParcelRecord[]> {
    if (DEMO_MODE) return mockHubParcels;
    const hubs = await hubService.getHubs(agencyId);
    const records = await Promise.all(hubs.map(h => hubService.getParcelRecords(h.id)));
    return records.flat();
  },

  async depositParcel(hubId: string, data: {
    missionId: string; packageId: string; trackingCode: string; recipientName: string;
  }): Promise<HubParcelRecord> {
    if (DEMO_MODE) return mockHubParcels[0];
    const dto = await apiClient.post<HubParcelRecordDto>(`/hubs/${hubId}/parcels`, data);
    return mapHubParcelRecord(dto);
  },

  async withdrawParcel(hubId: string, recordId: string, withdrawnBy: string): Promise<void> {
    if (DEMO_MODE) return;
    await apiClient.post(`/hubs/${hubId}/parcels/${recordId}/withdraw`, { withdrawnBy, identityVerified: true });
  },

  async processExpired(hubId: string): Promise<void> {
    if (DEMO_MODE) return;
    await apiClient.post(`/hubs/${hubId}/expired`, {});
  },
};
