'use client';

import { useState, useEffect, useCallback } from 'react';
import { DEMO_MODE } from '@/lib/config';

interface ServiceState<T> {
  data: T;
  loading: boolean;
  error: string | null;
}

/**
 * Hook générique pour charger des données via un service.
 *
 * En DEMO_MODE : `data` est initialisé avec `fallback`, pas de fetch réseau.
 * En mode LIVE  : fetch asynchrone, `loading = true` pendant la requête.
 */
export function useService<T>(
  loader: () => Promise<T>,
  fallback: T,
): ServiceState<T> & { refetch: () => void; setData: (d: T) => void } {
  const [state, setState] = useState<ServiceState<T>>({
    data: fallback,
    loading: !DEMO_MODE,
    error: null,
  });

  const fetch = useCallback(() => {
    if (DEMO_MODE) return;
    setState(s => ({ ...s, loading: true, error: null }));
    loader()
      .then(data => setState({ data, loading: false, error: null }))
      .catch(e => setState(s => ({ ...s, loading: false, error: (e as Error).message ?? 'Erreur serveur' })));
  }, []); // eslint-disable-line react-hooks/exhaustive-deps

  useEffect(() => { fetch(); }, [fetch]);

  const setData = useCallback((d: T) => setState(s => ({ ...s, data: d })), []);

  return { ...state, refetch: fetch, setData };
}
